import{_ as n,c as i,o as r,a1 as t}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Schnellstart: Orchestrierungsfunktionen | oh-my-opencode","description":"Installieren und beginnen Sie schnell mit oh-my-opencode. Lernen Sie grundlegende Orchestrierungsfunktionen und den Ultrawork-Modus. Absolvieren Sie Installation und Grundkonfiguration in 5 Minuten.","frontmatter":{"title":"Schnellstart: Orchestrierungsfunktionen | oh-my-opencode","sidebarTitle":"In 5 Minuten loslegen","subtitle":"Schnellstart: Orchestrierungsfunktionen","description":"Installieren und beginnen Sie schnell mit oh-my-opencode. Lernen Sie grundlegende Orchestrierungsfunktionen und den Ultrawork-Modus. Absolvieren Sie Installation und Grundkonfiguration in 5 Minuten.","order":10},"headers":[],"relativePath":"de/code-yeongyu/oh-my-opencode/start/index.md","filePath":"de/code-yeongyu/oh-my-opencode/start/index.md"}'),l={name:"de/code-yeongyu/oh-my-opencode/start/index.md"};function a(o,e,s,u,d,h){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="schnellstart" tabindex="-1">Schnellstart <a class="header-anchor" href="#schnellstart" aria-label="Permalink to &quot;Schnellstart&quot;">​</a></h1><p>Dieser Abschnitt hilft Ihnen, oh-my-opencode schnell zu installieren und zu verwenden – von der Grundkonfiguration über den Haupt-Orchestrator bis zum Ultrawork-Modus, der alle Funktionen mit einem Klick aktiviert.</p><h2 id="lernpfad" tabindex="-1">Lernpfad <a class="header-anchor" href="#lernpfad" aria-label="Permalink to &quot;Lernpfad&quot;">​</a></h2><p>Befolgen Sie diese Reihenfolge, um die grundlegenden Funktionen von oh-my-opencode schrittweise zu beherrschen:</p><h3 id="_1-schnelle-installation-und-konfiguration" tabindex="-1">1. <a href="./installation/">Schnelle Installation und Konfiguration</a> <a class="header-anchor" href="#_1-schnelle-installation-und-konfiguration" aria-label="Permalink to &quot;1. [Schnelle Installation und Konfiguration](./installation/)&quot;">​</a></h3><p>Absolvieren Sie die Installation von oh-my-opencode, die Provider-Konfiguration und die grundlegende Überprüfung.</p><ul><li>Installieren Sie oh-my-opencode</li><li>Konfigurieren Sie den AI-Provider (Claude, OpenAI, Gemini usw.)</li><li>Überprüfen Sie, ob die Konfiguration korrekt ist</li><li>Verstehen Sie die Struktur der Konfigurationsdatei</li></ul><h3 id="_2-kennenlernen-von-sisyphus-der-haupt-orchestrator" tabindex="-1">2. <a href="./sisyphus-orchestrator/">Kennenlernen von Sisyphus: Der Haupt-Orchestrator</a> <a class="header-anchor" href="#_2-kennenlernen-von-sisyphus-der-haupt-orchestrator" aria-label="Permalink to &quot;2. [Kennenlernen von Sisyphus: Der Haupt-Orchestrator](./sisyphus-orchestrator/)&quot;">​</a></h3><p>Verstehen Sie die Kernkonzepte der Agenten-Orchestrierung und lernen Sie die grundlegende Verwendung des Sisyphus-Agenten.</p><ul><li>Was ist ein Agenten-Orchestrierungssystem</li><li>Kernfunktionen des Sisyphus-Agenten</li><li>Grundlegende Verwendung und Best Practices</li><li>Verstehen Sie den Workflow der Multi-Modell-Zusammenarbeit</li></ul><h3 id="_3-ultrawork-modus-alle-funktionen-mit-einem-klick-aktivieren" tabindex="-1">3. <a href="./ultrawork-mode/">Ultrawork-Modus: Alle Funktionen mit einem Klick aktivieren</a> <a class="header-anchor" href="#_3-ultrawork-modus-alle-funktionen-mit-einem-klick-aktivieren" aria-label="Permalink to &quot;3. [Ultrawork-Modus: Alle Funktionen mit einem Klick aktivieren](./ultrawork-mode/)&quot;">​</a></h3><p>Lernen Sie, wie Sie das ultrawork-Schlüsselwort verwenden, um schnell alle professionellen Agenten und parallelen Aufgabenfunktionen zu aktivieren.</p><ul><li>Was ist der Ultrawork-Modus</li><li>Wie Sie das ultrawork-Schlüsselwort auslösen</li><li>Zusammenarbeit von 10 professionellen Agenten</li><li>Verwaltung paralleler Hintergrundaufgaben</li></ul><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><p>Bevor Sie mit diesem Abschnitt beginnen, stellen Sie sicher:</p><ul><li>Node.js 18+ ist installiert (Version 20 oder höher wird empfohlen)</li><li>Sie sind mit grundlegenden Befehlszeilenoperationen vertraut</li><li>Sie verfügen über mindestens einen API-Schlüssel für einen KI-Dienst (Claude, OpenAI oder Gemini)</li></ul><div class="tip custom-block"><p class="custom-block-title">Kein API-Schlüssel?</p><p>Wenn Sie noch keinen API-Schlüssel für einen KI-Dienst haben, können Sie mit Claude beginnen. Dies ist derzeit die empfohlene Wahl.</p></div><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Abschnitts können Sie mit folgenden Themen fortfahren:</p><ul><li><strong><a href="./../../platforms/provider-setup/">Plattformen und Integrationen</a></strong> - Vertiefen Sie Ihr Wissen über Multi-Provider-Konfiguration und Modellstrategien</li><li><strong><a href="./../../advanced/ai-agents-overview/">Erweiterte Funktionen</a></strong> - Erkunden Sie das vollständige Team aus 10 Agenten und erweiterte Funktionen</li></ul>',20)])])}const g=n(l,[["render",a]]);export{p as __pageData,g as default};
